import math


def round_half_even(x):
    floor_val = math.floor(x)
    diff = x - floor_val

    if diff < 0.5:
        return floor_val
    elif diff > 0.5:
        return floor_val + 1
    else:
        return floor_val if floor_val % 2 == 0 else floor_val + 1

